1	import React, { createContext, useContext, useEffect, useState } from 'react';
2	import { doc, updateDoc, increment } from 'firebase/firestore';
3	import { db } from '../firebase/config';
4	import { useAuth } from './AuthContext';
5	
6	const SubscriptionContext = createContext(null);
7	
8	export function useSubscription() {
9	  return useContext(SubscriptionContext);
10	}
11	
12	const TRIAL_DAYS = 14;
13	
14	export const PLANS = {
15	  free: {
16	    name: 'Free',
17	    trialDays: TRIAL_DAYS,
18	    // After trial ends, only these specific tools are accessible:
19	    allowedTools: ['marketing:seo-keyword-research', 'marketing:seo-meta-tags', 'marketing:instagram-audit'],
20	  },
21	  grow: {
22	    name: 'Grow',
23	    categories: ['marketing', 'content', 'digital'],
24	    allowedTools: ['strategy:business-plan'],
25	  },
26	  scale: {
27	    name: 'Scale',
28	    categories: ['marketing', 'content', 'digital', 'ecommerce', 'agency', 'creative'],
29	    allowedTools: ['strategy:business-plan'],
30	  },
31	  evolution: {
32	    name: 'Evolution',
33	    categories: ['marketing', 'content', 'digital', 'ecommerce', 'agency', 'creative', 'finance', 'startup', 'strategy'],
34	    allowedTools: [],
35	  },
36	  admin: {
37	    name: 'Admin',
38	    allAccess: true,
39	  },
40	};
41	
42	export function SubscriptionProvider({ children }) {
43	  const { currentUser, userProfile, refreshUserProfile } = useAuth();
44	  const [subscription, setSubscription] = useState('free');
45	  const [usageCount, setUsageCount] = useState(0);
46	  const [checkingSubscription, setCheckingSubscription] = useState(true);
47	
48	  // Backward compat: map legacy plan names to current ones
49	  const PLAN_ALIASES = { 'pro': 'grow', 'business': 'evolution' };
50	
51	  // Admin UID override — mirrors server-side ADMIN_UIDS check
52	  const ADMIN_UIDS = (process.env.REACT_APP_ADMIN_UIDS || '').split(',').map(s => s.trim()).filter(Boolean);
53	
54	  useEffect(() => {
55	    if (ADMIN_UIDS.includes(currentUser?.uid)) {
56	      setSubscription('admin');
57	      setCheckingSubscription(false);
58	      return;
59	    }
60	    if (userProfile) {
61	      const raw = userProfile.subscription || 'free';
62	      setSubscription(PLAN_ALIASES[raw] || raw);
63	      setUsageCount(userProfile.usageCount || 0);
64	      setCheckingSubscription(false);
65	    } else {
66	      setCheckingSubscription(false);
67	    }
68	  }, [userProfile, currentUser]); // eslint-disable-line react-hooks/exhaustive-deps
69	
70	  // --- Trial helpers ---
71	
72	  function getCreatedAtMs() {
73	    const createdAt = userProfile?.createdAt;
74	    if (!createdAt) return null;
75	    if (typeof createdAt.toMillis === 'function') return createdAt.toMillis();
76	    return new Date(createdAt).getTime();
77	  }
78	
79	  function isInTrial() {
80	    if (subscription !== 'free') return false;
81	    const ms = getCreatedAtMs();
82	    if (!ms) return false;
83	    return (Date.now() - ms) < TRIAL_DAYS * 24 * 60 * 60 * 1000;
84	  }
85	
86	  function trialDaysRemaining() {
87	    if (subscription !== 'free') return 0;
88	    const ms = getCreatedAtMs();
89	    if (!ms) return 0;
90	    const elapsed = Date.now() - ms;
91	    const remaining = TRIAL_DAYS * 24 * 60 * 60 * 1000 - elapsed;
92	    return remaining > 0 ? Math.ceil(remaining / (24 * 60 * 60 * 1000)) : 0;
93	  }
94	
95	  // --- Access functions ---
96	
97	  function getPlan() {
98	    return PLANS[subscription] || PLANS.free;
99	  }
100	
101	  function canUseSpecificTool(categoryId, toolId) {
102	    if (!currentUser) return false;
103	    const plan = getPlan();
104	    if (plan.allAccess) return true;
105	    if (isInTrial()) return true;
106	    if (plan.categories?.includes(categoryId)) return true;
107	    if (plan.allowedTools?.includes(`${categoryId}:${toolId}`)) return true;
108	    return false;
109	  }
110	
111	  // Category-level check — true if user can access ANY tool in the category
112	  function canUseTool(categoryId) {
113	    if (!currentUser) return false;
114	    const plan = getPlan();
115	    if (plan.allAccess) return true;
116	    if (isInTrial()) return true;
117	    if (plan.categories?.includes(categoryId)) return true;
118	    if (plan.allowedTools?.some((t) => t.startsWith(`${categoryId}:`))) return true;
119	    return false;
120	  }
121	
122	  function isCategoryLocked(categoryId) {
123	    const plan = getPlan();
124	    if (plan.allAccess) return false;
125	    if (isInTrial()) return false;
126	    if (plan.categories?.includes(categoryId)) return false;
127	    if (plan.allowedTools?.some((t) => t.startsWith(`${categoryId}:`))) return false;
128	    return true;
129	  }
130	
131	  async function trackUsage() {
132	    if (!currentUser) return;
133	    try {
134	      const userRef = doc(db, 'users', currentUser.uid);
135	      await updateDoc(userRef, { usageCount: increment(1) });
136	      setUsageCount((prev) => prev + 1);
137	    } catch (err) {
138	      console.error('Error tracking usage:', err);
139	    }
140	  }
141	
142	  function getPlanLimits() {
143	    return PLANS[subscription] || PLANS.free;
144	  }
145	
146	  const value = {
147	    subscription,
148	    usageCount,
149	    checkingSubscription,
150	    canUseTool,
151	    canUseSpecificTool,
152	    isCategoryLocked,
153	    isInTrial,
154	    trialDaysRemaining,
155	    trackUsage,
156	    getPlanLimits,
157	    PLANS,
158	    refreshUserProfile,
159	  };
160	
161	  return (
162	    <SubscriptionContext.Provider value={value}>
163	      {children}
164	    </SubscriptionContext.Provider>
165	  );
166	}
