43	function useCountUp(target, inView) {
44	  const [count, setCount] = useState(0);
45	  useEffect(() => {
46	    if (!inView) return;
47	    let frame;
48	    const start = performance.now();
49	    const duration = 1400;
50	    const tick = (now) => {
51	      const progress = Math.min((now - start) / duration, 1);
52	      const eased = 1 - Math.pow(1 - progress, 3);
53	      setCount(Math.floor(eased * target));
54	      if (progress < 1) frame = requestAnimationFrame(tick);
55	    };
56	    frame = requestAnimationFrame(tick);
57	    return () => cancelAnimationFrame(frame);
58	  }, [inView, target]);
59	  return count;
60	}
